    },
    {
      "query": "OpenAI announcement July 11 2026",
      "url": "https://www.cryptointegrat.com/p/ai-news-july-11-2026",
      "title": "AI News. July 11, 2026 - by Crypto Integrated",
      "snippet": "Daily AI news roundup dated July 11, 2026 covering the latest model, agent and industry developments across OpenAI, Anthropic and Google.",
      "expectedCategory": "industry"
    },
    {
      "query": "OpenAI announcement July 11 2026",
      "url": "https://www.tech-reader.blog/2026/07/ai-news-sat-july-11-2026.html",
      "title": "AI News - Weekly Recap for July 6-10 2026",
      "snippet": "Weekly AI recap published July 11, 2026 summarizing the week's model releases and agent-tooling news, including GPT-5.6 Sol/Terra/Luna availability from July 9.",
      "expectedCategory": "industry"
    },
    {
      "query": "OpenAI announcement July 11 2026",
      "url": "https://openai.com/index/openai-submits-confidential-s-1/",
      "title": "Confidential submission of draft S-1 to the SEC | OpenAI",
      "snippet": "OpenAI announces the confidential submission of a draft S-1 registration statement to the SEC, a step toward a potential public offering.",
